-- D&D 2024 class and subclass catalog.

CREATE TEMP TABLE _import_class_data (
    name TEXT PRIMARY KEY,
    hit_die TEXT NOT NULL
) ON COMMIT DROP;


SELECT name, hit_die
FROM _import_class_data
ON CONFLICT (name) DO UPDATE SET hit_die = EXCLUDED.hit_die;

CREATE TEMP TABLE _import_subclass_data (
    class_name TEXT NOT NULL,
    name TEXT NOT NULL,
    description TEXT,
    PRIMARY KEY (class_name, name)
) ON COMMIT DROP;


SELECT c.id, sd.name, sd.description
FROM _import_subclass_data sd
JOIN classes c ON c.name = sd.class_name
ON CONFLICT (class_id, name) DO UPDATE SET description = EXCLUDED.description;

COMMIT;
